def predict(triples: list[Triple]) -> str:
    """Generate a natural‑language description from a list of triples."""
    if not triples:
        return ""

    # Group triples by subject for better combination
    from collections import defaultdict

    subj_map: dict[str, list[Triple]] = defaultdict(list)
    for t in triples:
        subj_map[t.subject].append(t)

    # Helper to render a single predicate‑object pair
    def render_pair(s: str, p: str, o: str) -> str:
        if p == "birthDate":
            return f"{s} was born on {o}"
        if p == "birthYear":
            return f"{s} was born in {o}"
        if p == "birthPlace":
            return f"{s} was born in {o}"
        if p == "deathDate":
            return f"{s} died on {o}"
        if p == "deathPlace":
            return f"{s} died in {o}"
        if p == "origin":
            return f"{s} originates from {o}"
        if p == "genre":
            return f"{s} plays {o} music"
        if p == "instrument":
            return f"{s} plays {o}"
        if p == "occupation":
            return f"{s} is a {o}"
        if p == "associatedBand/associatedMusicalArtist":
            return f"{s} is a member of {o}"
        if p == "recordLabel":
            return f"{s} is signed to {o}"
        if p == "activeYearsStartYear":
            return f"{s} started their career in {o}"
        if p == "activeYearsEndYear":
            return f"{s} ended their career in {o}"
        if p == "nationality":
            return f"{s} is {o}"
        if p == "capital":
            return f"The capital of {s} is {o}"
        if p == "country":
            return f"{s} is in {o}"
        if p == "isPartOf":
            return f"{s} is part of {o}"
        if p in {"language", "officialLanguage"}:
            return f"The language of {s} is {o}"
        if p == "stylisticOrigin":
            return f"{s} originated from {o}"
        if p == "derivative":
            return f"{s} is a derivative of {o}"
        if p == "musicFusionGenre":
            return f"{s} fuses elements of {o}"
        if p == "musicSubgenre":
            return f"{s} is a subgenre of {o}"
        # fallback
        return f"{s} {p} {o}"

    sentences: list[str] = []

    for subject, tlist in subj_map.items():
        # Build main clause for the subject
        main_clauses: list[str] = []
        extra_clauses: list[str] = []

        # Detect if there is a genre triple to attach stylistic origin etc.
        genre_obj = None
        for t in tlist:
            if t.predicate == "genre":
                genre_obj = t.object
                main_clauses.append(render_pair(subject, t.predicate, t.object))
            elif t.predicate in {"stylisticOrigin", "derivative", "musicFusionGenre", "musicSubgenre"}:
                # will be attached as relative clause if possible
                extra_clauses.append((t.predicate, t.object))
            else:
                main_clauses.append(render_pair(subject, t.predicate, t.object))

        # Attach extra clauses to the genre if present
        if genre_obj and extra_clauses:
            rel_parts = []
            for p, o in extra_clauses:
                if p == "stylisticOrigin":
                    rel_parts.append(f"which originated from {o}")
                elif p == "derivative":
                    rel_parts.append(f"which is a derivative of {o}")
                elif p == "musicFusionGenre":
                    rel_parts.append(f"which fuses elements of {o}")
                elif p == "musicSubgenre":
                    rel_parts.append(f"which is a subgenre of {o}")
            # combine with commas
            rel_clause = ", ".join(rel_parts)
            # replace the last genre clause with enriched version
            for i, cl in enumerate(main_clauses):
                if genre_obj in cl:
                    main_clauses[i] = f"{subject} plays {genre_obj} music, {rel_clause}"
                    break

        # Assemble subject sentence
        if len(main_clauses) == 1:
            sentences.append(main_clauses[0])
        else:
            sentences.append(", ".join(main_clauses[:-1]) + ", and " + main_clauses[-1])

    # Combine all subject sentences into one paragraph
    if len(sentences) == 1:
        return sentences[0] + "."
    else:
        return " ".join(s.rstrip(".") + "." for s in sentences)

# EVOLVE-BLOCK-END

